// Type Definitions
const typeDefs = gql`
  enum InvoiceStatus {
    DRAFT
    PENDING
    PAID
    OVERDUE
    CANCELLED
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    unitPrice: Float!
    amount: Float!
  }

  type Invoice {
    id: ID!
    invoiceNumber: String!
    clientName: String!
    clientEmail: String!
    issueDate: String!
    dueDate: String!
    status: InvoiceStatus!
    items: [InvoiceItem!]!
    subtotal: Float!
    taxRate: Float!
    taxAmount: Float!
    totalAmount: Float!
    notes: String
    createdBy: String!
  }

  type Query {
    invoice(id: ID!): Invoice
    invoices(status: InvoiceStatus, limit: Int, offset: Int): InvoiceConnection!
  }

  type InvoiceConnection {
    invoices: [Invoice!]!
    totalCount: Int!
    hasMore: Boolean!
  }

  input InvoiceItemInput {
    description: String!
    quantity: Int!
    unitPrice: Float!
  }

  input CreateInvoiceInput {
    clientName: String!
    clientEmail: String!
    dueDate: String!
    items: [InvoiceItemInput!]!
    taxRate: Float
    notes: String
  }

  input UpdateInvoiceStatusInput {
    id: ID!
    status: InvoiceStatus!
  }

  type Mutation {
    createInvoice(input: CreateInvoiceInput!): Invoice!
    updateInvoiceStatus(input: UpdateInvoiceStatusInput!): Invoice!
    deleteInvoice(id: ID!): Boolean!
  }
`;

// Resolver Implementation
const resolvers = {
  Query: {
    invoice: (parent, { id }, context) => {
      // context.user is populated by authentication middleware
      const user = context.user;
      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoice = invoices.find((inv) => inv.id === id);

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      // Users can query any invoice they have the ID for
      // (as specified in requirements - no ownership check needed)
      return invoice;
    },

    invoices: (parent, { status, limit = 10, offset = 0 }, context) => {
      const user = context.user;
      if (!user) {
        throw new Error('Authentication required.');
      }

      let filteredInvoices = [...invoices];

      // Filter by status if provided
      if (status) {
        filteredInvoices = filteredInvoices.filter((inv) => inv.status === status);
      }

      const totalCount = filteredInvoices.length;
      const paginatedInvoices = filteredInvoices.slice(offset, offset + limit);
      const hasMore = offset + limit < totalCount;

      return {
        invoices: paginatedInvoices,
        totalCount,
        hasMore
      };
    }
  },

  Mutation: {
    createInvoice: (parent, { input }, context) => {
      const user = context.user;
      if (!user) {
        throw new Error('Authentication required.');
      }

      const { clientName, clientEmail, dueDate, items, taxRate = 0.10, notes } = input;

      // Validate items
      if (!items || items.length === 0) {
        throw new Error('Invoice must have at least one item.');
      }

      // Generate new invoice
      const newId = String(invoices.length + 1);
      const invoiceNumber = `INV-${String(invoices.length + 1).padStart(3, '0')}`;
      const issueDate = new Date().toISOString().split('T')[0];

      // Calculate item amounts and subtotal
      const processedItems = items.map((item, index) => ({
        id: `item-${Date.now()}-${index}`,
        description: item.description,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        amount: parseFloat((item.quantity * item.unitPrice).toFixed(2))
      }));

      const subtotal = parseFloat(
        processedItems.reduce((sum, item) => sum + item.amount, 0).toFixed(2)
      );
      const taxAmount = parseFloat((subtotal * taxRate).toFixed(2));
      const totalAmount = parseFloat((subtotal + taxAmount).toFixed(2));

      const newInvoice = {
        id: newId,
        invoiceNumber,
        clientName,
        clientEmail,
        issueDate,
        dueDate,
        status: 'PENDING',
        items: processedItems,
        subtotal,
        taxRate,
        taxAmount,
        totalAmount,
        notes: notes || null,
        createdBy: user.id
      };

      invoices.push(newInvoice);

      return newInvoice;
    },

    updateInvoiceStatus: (parent, { input }, context) => {
      const user = context.user;
      if (!user) {
        throw new Error('Authentication required.');
      }

      const { id, status } = input;

      const invoiceIndex = invoices.findIndex((inv) => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      // Validate status transitions
      const currentStatus = invoices[invoiceIndex].status;
      const validTransitions = {
        DRAFT: ['PENDING', 'CANCELLED'],
        PENDING: ['PAID', 'OVERDUE', 'CANCELLED'],
        OVERDUE: ['PAID', 'CANCELLED'],
        PAID: [],
        CANCELLED: []
      };

      if (!validTransitions[currentStatus].includes(status)) {
        throw new Error(
          `Cannot transition invoice from "${currentStatus}" to "${status}". Valid transitions: ${validTransitions[currentStatus].join(', ') || 'none'}.`
        );
      }

      invoices[invoiceIndex] = {
        ...invoices[invoiceIndex],
        status
      };

      return invoices[invoiceIndex];
    },

    deleteInvoice: (parent, { id }, context) => {
      const user = context.user;
      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoiceIndex = invoices.findIndex((inv) => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      invoices.splice(invoiceIndex, 1);

      return true;
    }
  },

  // Field-level resolver for computed/derived fields
  Invoice: {
    items: (parent) => {
      return parent.items || [];
    }
  }
};

// Simulated authentication middleware (already verified per requirements)
const authMiddleware = (req, res, next) => {
  // Authentication has already been verified upstream
  // This middleware attaches the verified user to the request
  const authHeader = req.headers.authorization || '';

  // Simulated user from verified token
  req.user = {
    id: 'user-101',
    email: 'user@example.com',
    name: 'Authenticated User',
    role: 'admin'
  };

  next();
};

async function startServer() {
  const app = express();

  // Apply auth middleware before Apollo
  app.use(authMiddleware);

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    context: ({ req }) => {
      // Pass authenticated user into GraphQL context
      return {
        user: req.user
      };
    },
    formatError: (error) => {
      console.error('GraphQL Error:', error.message);
      return {
        message: error.message,
        code: error.extensions?.code || 'INTERNAL_SERVER_ERROR',
        path: error.path
      };
    }
  });

  await server.start();

  server.applyMiddleware({ app, path: '/graphql' });

  const PORT = process.env.PORT || 4000;

  app.listen(PORT, () => {
    console.log(`Invoice Management GraphQL API running at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`\nExample queries:`);
    console.log(`  - Get invoice by ID: { invoice(id: "1") { id invoiceNumber clientName totalAmount status items { description amount } } }`);
    console.log(`  - List all invoices: { invoices { invoices { id invoiceNumber clientName totalAmount status } totalCount hasMore } }`);
    console.log(`  - Filter by status:  { invoices(status: PENDING) { invoices { id invoiceNumber status } totalCount } }`);
  });
}

startServer().catch((err) => {
  console.error('Failed to start server:', err);
});

module.exports = { typeDefs, resolvers };